        assert_eq!(normalize_title("war OF the WORLDS"), "War of the Worlds");
    }

    #[test]
    fn first_word_is_capitalized_even_if_small() {
        assert_eq!(normalize_title("a tale of TWO cities"), "A Tale of Two Cities");
    }

    #[test]
    fn tabs_and_newlines_also_count_as_whitespace() {
        assert_eq!(normalize_title("into\tthe\nwoods"), "Into the Woods");
    }

    #[test]
    fn handles_mixed_case_small_words_near_end() {
        assert_eq!(normalize_title("journey TO the center OF earth"), "Journey to the Center of Earth");
    }
}
"
  },
  "steps": [
    {
      "tool": "read_file",
      "file_path": "src/lib.rs"
    },
    {
      "tool": "apply_patch",
      "file_path": "src/lib.rs",
      "find": "pub fn normalize_title(input: &str) -> String {
    input
        .split(' ')
        .filter(|w| !w.is_empty())
        .map(|word| {
            let mut chars = word.chars();
            match chars.next() {
                Some(first) => {
                    let mut out = String::new();
                    out.push(first.to_ascii_uppercase());
                    out.push_str(&chars.as_str().to_ascii_lowercase());
                    out
                }
                None => String::new(),
            }
        })
        .collect::<Vec<_>>()
        .join(" ")
}
",
      "replace": "pub fn normalize_title(input: &str) -> String {
    let small = ["a", "an", "and", "as", "at", "but", "by", "for", "in", "nor", "of", "on", "or", "the", "to"];

    input
        .split_whitespace()
        .enumerate()
        .map(|(i, word)| {
            let lower = word.to_ascii_lowercase();
            if i != 0 && small.contains(&lower.as_str()) {
                lower
            } else {
                let mut chars = lower.chars();
                match chars.next() {
                    Some(first) => {
                        let mut out = String::new();
                        out.push(first.to_ascii_uppercase());
                        out.push_str(chars.as_str());
                        out
                    }
                    None => String::new(),
                }
            }
        })
        .collect::<Vec<_>>()
        .join(" ")
}
"
    },
    {
      "tool": "cargo_test",
      "expect_status": "success"
    }
  ],
  "final": "FINAL: Patched src/lib.rs to normalize all whitespace, lowercase common small words except at the start, and keep title casing for other words; cargo test passes."
