    let mut out = Vec::new();

    for word in input.split(' ') {
        if word.is_empty() {
            continue;
        }

        let lower = word.to_ascii_lowercase();
        let normalized = if lower.starts_with("mc") && lower.len() > 2 {
            let rest = &lower[2..];
            format!("Mc{}{}", rest[..1].to_ascii_uppercase(), &rest[1..])
        } else if lower.contains('-') {
            lower
                .split('-')
                .map(capitalize)
                .collect::<Vec<_>>()
                .join("-")
        } else {
            capitalize(&lower)
        };

        out.push(normalized);
    }

    out.join(" ")
}

fn capitalize(s: &str) -> String {
    let mut chars = s.chars();
    match chars.next() {
        Some(first) => format!("{}{}", first.to_ascii_uppercase(), chars.as_str()),
