  "files": {
    "Cargo.toml": "[package]
name = "normalize_title"
version = "0.1.0"
edition = "2021"

[lib]
path = "src/lib.rs"
",
    "src/lib.rs": "pub fn normalize_title(input: &str) -> String {
    input
        .split_whitespace()
        .map(|word| {
            let mut chars = word.chars();
            match chars.next() {
                Some(first) => {
                    let mut out = String::new();
                    for c in first.to_uppercase() {
                        out.push(c);
                    }
                    out.push_str(chars.as_str());
                    out
                }
                None => String::new(),
            }
        })
        .collect::<Vec<_>>()
        .join(" ")
}

#[cfg(test)]
mod tests {
    use super::normalize_title;

    #[test]
    fn trims_and_collapses_spaces() {
        assert_eq!(normalize_title("  rust   language handbook  "), "Rust Language Handbook");
    }

    #[test]
    fn keeps_minor_words_lowercase_in_the_middle() {
        assert_eq!(normalize_title("war and peace"), "War and Peace");
        assert_eq!(normalize_title("the lord of the rings"), "The Lord of the Rings");
    }

    #[test]
    fn capitalizes_minor_words_at_the_edges() {
        assert_eq!(normalize_title("the old man and the sea"), "The Old Man and the Sea");
        assert_eq!(normalize_title("of mice and men"), "Of Mice and Men");
    }

    #[test]
    fn preserves_hyphenated_word_boundaries() {
        assert_eq!(normalize_title("state-of-the-art design"), "State-of-the-Art Design");
        assert_eq!(normalize_title("mother-in-law tale"), "Mother-in-Law Tale");
    }

