",
    "src/lib.rs": "pub fn wrap_words(input: &str, width: usize) -> Vec<String> {
    if input.trim().is_empty() {
        return Vec::new();
    }
    if width == 0 {
        return input
            .split_whitespace()
            .map(|w| w.to_string())
            .collect();
    }

    let mut lines = Vec::new();
    let mut current = String::new();

    for word in input.split_whitespace() {
        if current.is_empty() {
            current.push_str(word);
        } else if current.len() + 1 + word.len() <= width {
            current.push(' ');
            current.push_str(word);
        } else {
            lines.push(current);
            current = word.to_string();
        }
    }

    if !current.is_empty() {
        lines.push(current);
    }

    lines
}

#[cfg(test)]
mod tests {
    use super::wrap_words;

    #[test]
    fn empty_or_whitespace_input_returns_no_lines() {
        assert!(wrap_words("", 10).is_empty());
        assert!(wrap_words("   \n\t  ", 3).is_empty());
    }

    #[test]
    fn packs_multiple_words_per_line_when_they_fit() {
        let got = wrap_words("alpha beta gamma delta", 11);
        assert_eq!(got, vec!["alpha beta", "gamma delta"]);
    }

    #[test]
    fn preserves_long_word_without_splitting() {
        let got = wrap_words("tiny enormousword small", 5);
        assert_eq!(got, vec!["tiny", "enormousword", "small"]);
    }

    #[test]
    fn width_zero_places_each_word_on_its_own_line() {
        let got = wrap_words("a bb   ccc", 0);
        assert_eq!(got, vec!["a", "bb", "ccc"]);
    }

    #[test]
    fn ignores_extra_internal_whitespace() {
        let got = wrap_words("red   blue\n\n green", 8);
        assert_eq!(got, vec!["red blue", "green"]);
    }
}
